func solve(nums []int64, k int64) int64 {
    n_int := len(nums)
    k_int := int(k)
    if n_int == 0 {
        return 0
    }

    prefix := make([]int64, n_int+1)
    for i := 1; i <= n_int; i++ {
        prefix[i] = prefix[i-1] ^ nums[i-1]
    }

    low := int64(-1 << 63)
    high := int64(1<<63 - 1)

    for i := 0; i < 64; i++ {
        if low == high {
            break
        }
        mid := low + int64((uint64(high) - uint64(low)) / 2
        if feasible(mid, n_int, k_int, prefix) {
            high = mid
        } else {
            low = mid + 1
        }
    }
    return low
}

func feasible(candidate int64, n, k int, prefix []int64) bool {
    dp := make([][]bool, n+1)
    for i := range dp {
        dp[i] = make([]bool, k+1)
    }
    dp[0][0] = true

    for j := 1; j <= k; j++ {
