            found := false
            for t := j-1; t < i; t++ {
                if dp[t][j-1] {
                    xorVal := prefix[i] ^ prefix[t]
                    if xorVal <= candidate {
                        found = true
                        break
                    }
                }
            }
            dp[i][j] = found
        }
    }

    return dp[n][k]
}
